var net     = global.get('net');
var socket  = context.get('socket');
var kaTimer = context.get('kaTimer');

if (socket && !socket.destroyed) {
    return null;
}

if (kaTimer) { clearInterval(kaTimer); context.set('kaTimer', null); }

var maps = global.get('cotMaps');
var colorMap = maps.colorMap;
var iconMap = maps.iconMap;
var affiliationNames = maps.affiliationNames;

function getIcon(parts) {
    for (var len = parts.length - 2; len >= 1; len--) {
        var key = parts.slice(2, 2 + len).join('-');
        if (iconMap[key]) return iconMap[key];
    }
    return 'fa-question-circle';
}

function calcOpacity(startStr, staleStr) {
    if (!startStr || !staleStr) return 1.0;
    var startMs = new Date(startStr).getTime();
    var staleMs = new Date(staleStr).getTime();
    var nowMs   = Date.now();
    if (isNaN(startMs) || isNaN(staleMs)) return 1.0;
    if (nowMs < staleMs) return 1.0;
    var fadeDuration = staleMs - startMs;
    if (fadeDuration <= 0) return 0;
    var fadeEnd = staleMs + fadeDuration;
    if (nowMs >= fadeEnd) return 0;
    return 1.0 - ((nowMs - staleMs) / fadeDuration);
}

function parseRemarks(raw) {
    var parts = (raw || '').split(' | ');
    return {
        summary:  parts[0] || '',
        location: parts[1] || '',
        source:   parts[2] || '',
        severity: parts[3] || '',
        url:      parts[4] || ''
    };
}

function buildTooltip(callsign, r) {
    return callsign;
}

function buildPopup(callsign, r, color) {
    var html = '<div style="font-family:sans-serif;font-size:13px;max-width:300px;">';
    if (r.location) html += '<b>' + r.location + '</b><br>';
    if (r.summary)  html += r.summary + '<br>';
    if (r.source || r.severity) {
        html += '<span style="color:#888;font-size:11px;">';
        var meta = [];
        if (r.source)   meta.push(r.source);
        if (r.severity) meta.push(r.severity);
        html += meta.join(' &middot; ');
        html += '</span>';
    }
    if (r.url) {
        html += '<br><a href="' + r.url + '" target="_blank" '
             +  'style="color:#4A90D9;font-size:12px;">View details &rarr;</a>';
    }
    html += '</div>';
    return html;
}

function makeSA(uid) {
    var now   = new Date().toISOString();
    var stale = new Date(Date.now() + 300000).toISOString();
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
        + '<event version="2.0" uid="' + uid + '" type="a-f-G-U-C"'
        + ' time="' + now + '" start="' + now + '" stale="' + stale + '" how="m-g">'
        + '<point lat="0" lon="0" hae="0" ce="9999999" le="9999999"/>'
        + '<detail><contact endpoint="*:-1:stcp" callsign="CrypTAK-WebMap"/></detail>'
        + '</event>';
}

function connectToFTS() {
    var existing = context.get('socket');
    if (existing && !existing.destroyed) return;

    // Unique UID per connection to avoid FTS zombie fd collision
    var connId = context.get('connId') || 0;
    connId++;
    context.set('connId', connId);
    var myUid = 'CrypTAK-NR-' + connId;

    var s = new net.Socket();
    var buf = '';

    s.connect(8087, '192.168.50.120', function() {
        node.log('FTS connected as ' + myUid);
        context.set('retryCount', 0);
        s.write(makeSA(myUid));
        var timer = setInterval(function() {
            if (s && !s.destroyed) {
                s.write(makeSA(myUid));
            } else {
                clearInterval(timer);
                context.set('kaTimer', null);
            }
        }, 30000);
        context.set('kaTimer', timer);
    });

    s.on('data', function(data) {
        buf += data.toString();
        var endTag = '</event>';
        var idx;
        while ((idx = buf.indexOf(endTag)) !== -1) {
            var xml = buf.substring(0, idx + endTag.length);
            buf = buf.substring(idx + endTag.length);
            try {
                var typeM = xml.match(/\btype="([^"]+)"/);
                if (!typeM || !typeM[1].startsWith('a-')) continue;

                var uidM = xml.match(/\buid="([^"]+)"/);
                if (!uidM || uidM[1].startsWith('CrypTAK-NR-')) continue;

                var latM = xml.match(/\blat="([^"]+)"/);
                var lonM = xml.match(/\blon="([^"]+)"/);
                if (!latM || !lonM) continue;

                var lat = parseFloat(latM[1]);
                var lon = parseFloat(lonM[1]);
                if (lat === 0 && lon === 0) continue;

                var csM = xml.match(/callsign="([^"]+)"/);
                var cs  = csM ? csM[1] : (uidM ? uidM[1] : 'Unknown');
                if (cs === 'CrypTAK-WebMap') continue;

                var parts = typeM[1].split('-');
                var color = colorMap[parts[1] || 'u'] || '#888888';
                var icon  = getIcon(parts);

                var remM = xml.match(/<remarks[^>]*>([^<]*)<\/remarks>/);
                var r = parseRemarks(remM ? remM[1] : '');

                var startM = xml.match(/\bstart="([^"]+)"/);
                var staleM = xml.match(/\bstale="([^"]+)"/);
                var opacity = calcOpacity(
                    startM ? startM[1] : null,
                    staleM ? staleM[1] : null
                );

                if (opacity <= 0.05) {
                    var cache = flow.get('takMarkers') || {};
                    delete cache[cs];
                    flow.set('takMarkers', cache);
                    node.send({ payload: { name: cs, deleted: true } });
                    continue;
                }

                var affCode = parts[1] || 'u';
                var layerName = affiliationNames[affCode] || 'TAK Other';
                var ttlSec = 300;
                if (staleM && staleM[1]) {
                    var stMs = new Date(staleM[1]).getTime();
                    if (!isNaN(stMs)) ttlSec = Math.max(60, Math.round((stMs - Date.now()) / 1000));
                }

                var marker = {
                    name:      cs,
                    lat:       lat,
                    lon:       lon,
                    layer:     layerName,
                    icon:      icon,
                    iconColor: color,
                    tooltip:   buildTooltip(cs, r),
                    popup:     buildPopup(cs, r, color),
                    opacity:   Math.round(opacity * 100) / 100,
                    ttl:       ttlSec
                };
                var cache = flow.get('takMarkers') || {};
                cache[cs] = marker;
                flow.set('takMarkers', cache);
                node.send({ payload: marker });
            } catch(e) { node.warn('CoT parse error: ' + e.message); }
        }
    });

    s.on('error', function(e) {
        node.warn('FTS socket error: ' + e.message);
        var t = context.get('kaTimer');
        if (t) { clearInterval(t); context.set('kaTimer', null); }
        s.destroy();
        context.set('socket', null);
    });

    s.on('close', function() {
        node.warn('FTS socket closed (' + myUid + ')');
        var t = context.get('kaTimer');
        if (t) { clearInterval(t); context.set('kaTimer', null); }
        context.set('socket', null);
        var retries = context.get('retryCount') || 0;
        if (retries < 5) {
            context.set('retryCount', retries + 1);
            var delay = (retries + 1) * 2000;
            node.warn('Retry ' + (retries + 1) + '/5 in ' + (delay/1000) + 's');
            setTimeout(function() { connectToFTS(); }, delay);
        } else {
            node.warn('FTS: 5 retries exhausted, waiting for inject cycle');
            context.set('retryCount', 0);
        }
    });

    context.set('socket', s);
}

connectToFTS();
return null;

if (!msg.payload || !msg.payload.features) { node.warn('States GeoJSON failed'); return null; }
flow.set('statesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' state features');
msg.payload = { command: { map: {
    overlay: 'US States',
    geojson: flow.get('statesGeoJSON'),
    opt: { style: { color: '#444', weight: 1.5, fill: false } },
    visible: false, fit: false, clickable: false
}}};
return msg;

if (!msg.payload || !msg.payload.features) { node.warn('Counties GeoJSON failed'); return null; }
flow.set('countiesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' county features');
msg.payload = { command: { map: {
    overlay: 'US Counties',
    geojson: flow.get('countiesGeoJSON'),
    opt: { style: { color: '#888', weight: 0.7, fill: false } },
    visible: false, fit: false, clickable: false
}}};
return msg;

var data = msg.payload;
if (!data || !data.features) { node.warn('NOAA API failed: ' + JSON.stringify(msg.statusCode)); return null; }

var now = Date.now();
var sevStyle = {
    'Extreme':  { stroke: '#CC0000', fillColor: '#FF0000', fillOpacity: 0.40 },
    'Severe':   { stroke: '#CC4400', fillColor: '#FF6600', fillOpacity: 0.30 },
    'Moderate': { stroke: '#AAAA00', fillColor: '#FFEE00', fillOpacity: 0.22 },
    'Minor':    { stroke: '#0055AA', fillColor: '#3399FF', fillOpacity: 0.15 },
    'Unknown':  { stroke: '#555555', fillColor: '#999999', fillOpacity: 0.10 }
};

var features = [];
data.features.forEach(function(f) {
    if (!f.geometry) return;
    if (f.properties.expires && new Date(f.properties.expires).getTime() < now) return;
    var sev = f.properties.severity || 'Unknown';
    var sp  = sevStyle[sev] || sevStyle['Unknown'];
    var feat = JSON.parse(JSON.stringify(f));
    feat.properties.style = { color: sp.stroke, fillColor: sp.fillColor, fillOpacity: sp.fillOpacity, weight: 2 };
    feat.properties.name = feat.properties.event || 'Alert';
    features.push(feat);
});

node.log('NOAA: ' + features.length + ' active alerts');
var fc = { type: 'FeatureCollection', features: features };
flow.set('noaaGeoJSON', fc);

// Clear old overlay then send fresh one
node.send({ payload: { command: { map: { overlay: 'NOAA Alerts', delete: true } } } });
msg.payload = { command: { map: {
    overlay: 'NOAA Alerts',
    geojson: fc,
    opt: { style: { weight: 2 } },
    visible: true, fit: false
}}};
return msg;

// ── Owned Meshtastic nodes whitelist ──────────────────────────────────────
// Add your nodes as '!hexid': 'display name'
// Node hex ID shown in Meshtastic app: Radio Config → User → Node ID
var ownedNodes = {
    '!55c6ddbc': 'T-Beam',
};
flow.set('meshOwnedNodes', ownedNodes);
node.log('Mesh whitelist loaded: ' + Object.keys(ownedNodes).length + ' owned nodes');
return null;

if (msg.topic.indexOf('/json/') === -1) return null;

var payload = msg.payload;
if (!payload || !payload.from) return null;

var nodeId   = '!' + payload.from.toString(16).padStart(8, '0');
var msgType  = payload.type;
var registry = flow.get('meshRegistry') || {};
registry[nodeId] = registry[nodeId] || { id: nodeId };

if (msgType === 'nodeinfo' && payload.payload) {
    var info = payload.payload;
    registry[nodeId].name = info.longname || info.shortname || nodeId;
    flow.set('meshRegistry', registry);
    return null;
}

if (msgType === 'position' && payload.payload) {
    var pos = payload.payload;
    var lat = (pos.latitude_i  || 0) / 1e7;
    var lon = (pos.longitude_i || 0) / 1e7;
    if (lat === 0 && lon === 0) return null;

    registry[nodeId].lat = lat;
    registry[nodeId].lon = lon;
    flow.set('meshRegistry', registry);

    var ownedNodes = flow.get('meshOwnedNodes') || {};
    var isOwned    = ownedNodes.hasOwnProperty(nodeId);
    var name       = ownedNodes[nodeId] || registry[nodeId].name || nodeId;

    var meshMarker = {
        name:      name,
        lat:       lat,
        lon:       lon,
        layer:     'Meshtastic',
        icon:      'fa-dot-circle-o',
        iconColor: isOwned ? 'blue' : 'green',
        tooltip:   name + ' (' + nodeId + ')',
        ttl:       600
    };
    var meshCache = flow.get('meshMarkers') || {};
    meshCache[name] = meshMarker;
    flow.set('meshMarkers', meshCache);
    return { payload: meshMarker };
}

return null;

if (!msg.payload || msg.payload.action !== 'connected') return null;
var sid = msg._sessionid;
var msgs = [];

// Branding
msgs.push({ payload: { command: { toptitle: 'CrypTAK WebMap' } }, _sessionid: sid });
msgs.push({ payload: { command: { toplogo: '/cryptak-logo.png' } }, _sessionid: sid });
msgs.push({ payload: { command: { coords: 'mgrs' } }, _sessionid: sid });
var legend = flow.get('legendHtml');
if (legend) msgs.push({ payload: { command: { legend: legend } }, _sessionid: sid });

// GeoJSON overlays
var stGeo = flow.get('statesGeoJSON');
if (stGeo) msgs.push({ payload: { command: { map: { overlay: 'US States', geojson: stGeo, opt: { style: { color: '#444', weight: 1.5, fill: false } }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var coGeo = flow.get('countiesGeoJSON');
if (coGeo) msgs.push({ payload: { command: { map: { overlay: 'US Counties', geojson: coGeo, opt: { style: { color: '#888', weight: 0.7, fill: false } }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var noaaGeo = flow.get('noaaGeoJSON');
if (noaaGeo && noaaGeo.features && noaaGeo.features.length > 0) msgs.push({ payload: { command: { map: { overlay: 'NOAA Alerts', geojson: noaaGeo, opt: { style: { weight: 2 } }, visible: true, fit: false } } }, _sessionid: sid });

// TAK markers
var takCache = flow.get('takMarkers') || {};
var tKeys = Object.keys(takCache);
for (var i = 0; i < tKeys.length; i++) {
    var m = Object.assign({}, takCache[tKeys[i]]);
    msgs.push({ payload: m, _sessionid: sid });
}

// Mesh markers
var meshCache = flow.get('meshMarkers') || {};
var mKeys = Object.keys(meshCache);
for (var j = 0; j < mKeys.length; j++) {
    msgs.push({ payload: meshCache[mKeys[j]], _sessionid: sid });
}

node.log('Replaying ' + msgs.length + ' items to session ' + sid);
return [msgs];
